package com.themuffinman.app.vision.service;
import com.themuffinman.app.vision.model.VisionConversation; import org.springframework.stereotype.Service;
@Service public class VisionCreateAvailabilityExceptionExecutionAdapter implements VisionCapabilityExecutionAdapter { private final VisionBusinessAvailabilityMutationService service; public VisionCreateAvailabilityExceptionExecutionAdapter(VisionBusinessAvailabilityMutationService s){service=s;} public String capabilityId(){return "create_availability_exception";} public VisionExecutionResult execute(VisionConversation c){try{service.createException(c.getSlotData(),c.getOwner());return VisionExecutionResult.executedAction(capabilityId());}catch(RuntimeException e){return VisionExecutionResult.blocked("The availability exception could not be created.");}} }
